#!/usr/bin/env node
/**
 * Ensure `open-source/gnosis/lean-minimal/Lean` points at `../lean/Lean` (directory symlink).
 * Safe to run repeatedly; no-op if the link already exists and matches.
 *
 * Used before `lake build` in CI or fresh checkouts (Lake needs sources under the package root).
 */
import fs from 'node:fs';
import path from 'node:path';
import { fileURLToPath } from 'node:url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const pkgRoot = path.resolve(__dirname, '..');
const linkPath = path.join(pkgRoot, 'lean-minimal', 'Lean');
const targetPath = path.join(pkgRoot, 'lean', 'Lean');

function main() {
  if (fs.existsSync(linkPath)) {
    const st = fs.lstatSync(linkPath);
    if (st.isSymbolicLink()) {
      const resolved = fs.realpathSync(linkPath);
      if (resolved === fs.realpathSync(targetPath)) return;
    }
    console.error(`prepare-lean-minimal: ${linkPath} exists and is not the expected symlink; remove it and re-run`);
    process.exit(2);
  }
  fs.symlinkSync(path.relative(path.dirname(linkPath), targetPath), linkPath, 'dir');
  console.log(`prepare-lean-minimal: linked ${path.relative(pkgRoot, linkPath)} -> ../lean/Lean`);
}

main();
